import type {
  FilterFieldKeySuggestionConfig,
  FilterFieldValidatorMap,
  FilterFieldValuePredicateItem,
  FilterFieldValueSuggestionGroupConfig,
} from '../types/validation.js';
import {
  isFilterFieldValidatorMapDurationSpecification,
  isFilterFieldValidatorMapTypeSpecification,
  isFilterFieldValueSuggestionGroupConfig,
} from './validation-utils/type-guards.js';

type MigratedResult = {
  valueType?: FilterFieldKeySuggestionConfig['valueType'];
  valuePredicate?: FilterFieldKeySuggestionConfig['valuePredicate'];
};

/**
 * Migrates a `valuePredicate` value (any form except a function):
 * - Single type spec `{ type: ... }` → extracted to `valueType`
 * - Single duration `{ value, unit }` → converted to string
 * - Single `FilterFieldValueSuggestionGroupConfig` → duration-converts `.suggestions`
 * - Array → delegates to `migrateValuePredicateArray`
 * - Anything else (plain string / number / boolean / rich value) → passed through
 */
function migrateValuePredicate(
  valuePredicate: NonNullable<FilterFieldKeySuggestionConfig['valuePredicate']>,
): MigratedResult {
  if (typeof valuePredicate === 'function') {
    return { valuePredicate };
  }

  if (isFilterFieldValidatorMapTypeSpecification(valuePredicate)) {
    const raw = valuePredicate.type;
    const types = Array.isArray(raw) ? raw : [raw];
    const valueType = normalizeCollectedTypes([...new Set(types)]);
    return { valueType };
  }

  if (isFilterFieldValidatorMapDurationSpecification(valuePredicate)) {
    return { valuePredicate: `${valuePredicate.value}${valuePredicate.unit}` };
  }

  if (isFilterFieldValueSuggestionGroupConfig(valuePredicate)) {
    return {
      valuePredicate: {
        ...valuePredicate,
        suggestions: valuePredicate.suggestions.map(migrateValuePredicateItem),
      },
    };
  }

  if (Array.isArray(valuePredicate)) {
    return migrateValuePredicateArray(valuePredicate);
  }

  // Plain string / number / boolean / FilterFieldRichValuePredicate — pass through
  return { valuePredicate };
}

/**
 * NOTE:
 * This util is supposed to be used as a one-off migration helper. If you are dynamically generating `FilterFieldValidatorMap`
 * objects, you should update your code to produce the new format directly instead of using this function.
 *
 * Converts a `FilterFieldValidatorMap` from the deprecated object notation of `keyPredicates`
 * to the new array notation.
 *
 * The following transformations are applied:
 * - Each object key is moved into the `key` field of a `FilterFieldKeySuggestionConfig`.
 * - A bare type predicate (`{ type: 'String' }`) used as valuePredicate for a key is
 *   moved to the `valueType` prop.
 * - A `FilterFieldValidatorMapTypePredicate` used inside a `valuePredicate` array
 *   is extracted to `valueType`. If it was the only item in a `valuePredicate` array, that
 *   array is dropped entirely.
 * - Multiple type predicates in a `valuePredicate` array are merged and deduplicated into
 *   a single `valueType`.
 * - Deprecated `FilterFieldDuration` objects in `valuePredicate` (and inside
 *   `FilterFieldValueSuggestionGroupConfig.suggestions`) are converted to their string
 *   equivalents (e.g. `{ value: 10, unit: 'ms' }` → `'10ms'`).
 * - All other configuration props (`comparisonOperators`, `fallbackKey`,
 *   `suggestStatementOnValueMatch`, `displayValue`, `details`) are preserved as-is.
 *
 * If `keyPredicates` is already in array notation or is `undefined`, the original map
 * object is returned unchanged.
 *
 * @example
 * ```ts
 * const validatorMap = migrateFilterFieldKeyPredicatesToArray({
 *   keyPredicates: {
 *     myKey1: { type: 'String' },
 *     myKey2: { valuePredicate: { type: ['String', 'Number'] }, comparisonOperators: ['equals'] },
 *     myKey3: { valuePredicate: [{ type: 'String' }, 'literal1', 'literal2'] },
 *     myKey4: { valuePredicate: [{ value: 10, unit: 'ms' }, { value: 1, unit: 's' }] },
 *   },
 * });
 * // Result:
 * // {
 * //   keyPredicates: [
 * //     { key: 'myKey1', valueType: 'String' },
 * //     { key: 'myKey2', valueType: ['String', 'Number'], comparisonOperators: ['equals'] },
 * //     { key: 'myKey3', valueType: 'String', valuePredicate: ['literal1', 'literal2'] },
 * //     { key: 'myKey4', valuePredicate: ['10ms', '1s'] },
 * //   ],
 * // }
 * ```
 * @public
 */
export function migrateFilterFieldKeyPredicatesToArray(
  validatorMap: FilterFieldValidatorMap,
): FilterFieldValidatorMap {
  const { keyPredicates } = validatorMap;

  if (keyPredicates === undefined || Array.isArray(keyPredicates)) {
    return validatorMap;
  }

  const result: FilterFieldKeySuggestionConfig[] = Object.entries(
    keyPredicates,
  ).map(([key, config]) => {
    // Bare type spec used as the whole config: `{ myKey: { type: 'String' } }`
    if (isFilterFieldValidatorMapTypeSpecification(config)) {
      const raw = config.type;
      const types = Array.isArray(raw) ? raw : [raw];
      return { key, valueType: normalizeCollectedTypes([...new Set(types)]) };
    }

    const { valuePredicate, ...rest } = config;

    if (valuePredicate === undefined) {
      return { key, ...rest };
    }

    const { valueType, valuePredicate: migratedPredicate } =
      migrateValuePredicate(valuePredicate);

    return {
      key,
      ...rest,
      ...(valueType !== undefined && { valueType }),
      ...(migratedPredicate !== undefined && {
        valuePredicate: migratedPredicate,
      }),
    };
  });

  return { ...validatorMap, keyPredicates: result };
}

/**
 * Migrates a single `FilterFieldValuePredicateItem`:
 * converts deprecated `FilterFieldDuration` objects to their string equivalents (e.g. `'10ms'`).
 * All other items are returned unchanged.
 */
function migrateValuePredicateItem(
  item: FilterFieldValuePredicateItem,
): FilterFieldValuePredicateItem {
  if (isFilterFieldValidatorMapDurationSpecification(item)) {
    return `${item.value}${item.unit}`;
  }
  return item;
}

/**
 * Flattens and deduplicates the collected type strings and normalises single-element
 * arrays to a scalar value.
 */
function normalizeCollectedTypes(
  types: string[],
): FilterFieldKeySuggestionConfig['valueType'] | undefined {
  if (types.length === 0) {
    return undefined;
  }
  // Cast is safe — the strings come directly from FilterFieldValidatorMapTypePredicate.type
  return types.length === 1
    ? (types[0] as FilterFieldKeySuggestionConfig['valueType'])
    : (types as FilterFieldKeySuggestionConfig['valueType']);
}

/**
 * Migrates a `valuePredicate` array: extracts all type-spec items into `valueType`,
 * converts duration items to strings, and duration-converts suggestions inside groups.
 * Type specs that appear inside `FilterFieldValueSuggestionGroupConfig.suggestions` are
 * left in place — they cannot be lifted out to the key-level `valueType`.
 */
function migrateValuePredicateArray(
  items: Array<
    FilterFieldValuePredicateItem | FilterFieldValueSuggestionGroupConfig
  >,
): MigratedResult {
  const collectedTypes: string[] = [];
  const remaining: Array<
    FilterFieldValuePredicateItem | FilterFieldValueSuggestionGroupConfig
  > = [];

  for (const item of items) {
    if (isFilterFieldValidatorMapTypeSpecification(item)) {
      const types = Array.isArray(item.type) ? item.type : [item.type];
      for (const t of types) {
        if (!collectedTypes.includes(t)) {
          collectedTypes.push(t);
        }
      }
    } else if (isFilterFieldValueSuggestionGroupConfig(item)) {
      remaining.push({
        ...item,
        suggestions: item.suggestions.map(migrateValuePredicateItem),
      });
    } else {
      remaining.push(migrateValuePredicateItem(item));
    }
  }

  const valueType = normalizeCollectedTypes(collectedTypes);
  const valuePredicate =
    remaining.length === 0
      ? undefined
      : remaining.length === 1
      ? remaining[0]
      : remaining;

  return { valueType, valuePredicate };
}
